<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Signup Success</title>
    <script src="https://cdn.tailwindcss.com"></script>
</head>

<body>
    <section>
        <div class="min-h-screen bg-radial from-gray-300 to-gray-600 flex items-center justify-center px-4">
            <div class="max-w-md w-full bg-white p-8 rounded-lg shadow-md text-center">
                <div class="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-green-100">
                    <svg class="h-6 w-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                </div>
                <h2 class="mt-3 text-lg font-medium text-gray-900">
                    Vendor Registration Successful!
                </h2>
                <p class="mt-2 text-sm text-gray-500">
                    Thank you for registering as a vendor. Your application is under review.
                    We will contact you shortly.
                </p>
                <div class="mt-6">
                    <a href="/" class="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700">
                        Return to Home
                    </a>
                </div>
            </div>
        </div>
    </section>
</body>

</html>
